import { useState } from "react";
import { createPost } from "../firebase/posts";
import AIWritingAssistant from "./ai/AIWritingAssistant";
import AITagGenerator from "./ai/AITagGenerator";
import { generateBlog } from "../ai/aiService";
import toast from "react-hot-toast";

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish, currentUser }) {
  const [form, setForm] = useState({
    title: "",
    author: currentUser?.displayName || "",
    content: "",
  });

  const [aiTags, setAiTags] = useState([]);
  const [activeTab, setActiveTab] = useState("write");
  const [publishing, setPublishing] = useState(false);

  // 🔥 AI states
  const [aiDraft, setAiDraft] = useState("");
  const [showPreview, setShowPreview] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);

  const set = (k, v) => {
    setForm((f) => ({ ...f, [k]: v }));
  };

  // 🔥 GENERATE BLOG
  const handleGenerateBlog = async () => {
    if (!form.title.trim()) {
      toast.error("Enter title first");
      return;
    }

    setAiLoading(true);
    setShowPreview(true);

    try {
      const content = await generateBlog(form.title);
      setAiDraft(content);
      toast.success("AI draft ready!");
    } catch {
      toast.error("AI failed");
    }

    setAiLoading(false);
  };

  // 🔥 PUBLISH
  const handlePublish = async () => {
    if (!form.title || !form.content) {
      toast.error("Fill all fields");
      return;
    }

    setPublishing(true);

    const postData = {
      ...form,
      tags: aiTags,
    };

    if (isDemo) {
      onDemoPublish?.(postData);
    } else {
      await createPost(postData);
    }

    toast.success("Post published!");
    onPublished?.();
    onClose();
  };

  return (
    <div style={s.backdrop}>
      <div style={s.modal}>
        <button style={s.closeBtn} onClick={onClose}>✕</button>

        <h2 style={s.title}>Write Post</h2>

        {/* TABS */}
        <div style={s.tabs}>
          <button
            style={activeTab === "write" ? s.activeTab : s.tab}
            onClick={() => setActiveTab("write")}
          >
            Write
          </button>
          <button
            style={activeTab === "ai" ? s.activeTab : s.tab}
            onClick={() => setActiveTab("ai")}
          >
            AI
          </button>
        </div>

        {/* WRITE */}
        {activeTab === "write" && (
          <>
            <input
              style={s.input}
              placeholder="Title"
              value={form.title}
              onChange={(e) => set("title", e.target.value)}
            />

            <textarea
              style={s.textarea}
              placeholder="Write your content..."
              value={form.content}
              onChange={(e) => set("content", e.target.value)}
            />

            <AITagGenerator
              title={form.title}
              content={form.content}
              onTagsGenerated={setAiTags}
            />

            <div style={s.tags}>
              {aiTags.map((t) => (
                <span key={t} style={s.tag}>#{t}</span>
              ))}
            </div>

            <button style={s.publishBtn} onClick={handlePublish}>
              {publishing ? "Publishing..." : "🚀 Publish"}
            </button>
          </>
        )}

        {/* AI TAB */}
        {activeTab === "ai" && (
          <>
            <button style={s.aiBtn} onClick={handleGenerateBlog}>
              ✍️ Generate Blog
            </button>

            {/* PREVIEW */}
            {showPreview && (
              <div style={s.previewBox}>
                <h4 style={s.previewTitle}>🤖 AI Draft</h4>

                {aiLoading ? (
                  <p style={s.loading}>AI is writing...</p>
                ) : (
                  <div style={s.previewContent}>{aiDraft}</div>
                )}

                {!aiLoading && (
                  <div style={s.previewActions}>
                    <button
                      style={s.acceptBtn}
                      onClick={() => {
                        setForm((f) => ({ ...f, content: aiDraft }));
                        setShowPreview(false);
                        setActiveTab("write");
                      }}
                    >
                      ✅ Use
                    </button>

                    <button
                      style={s.regenBtn}
                      onClick={handleGenerateBlog}
                    >
                      🔄 Regenerate
                    </button>

                    <button
                      style={s.rejectBtn}
                      onClick={() => setShowPreview(false)}
                    >
                      ❌ Close
                    </button>
                  </div>
                )}
              </div>
            )}

            <AIWritingAssistant
              title={form.title}
              content={form.content}
            />
          </>
        )}
      </div>
    </div>
  );
}

const s = {
  backdrop: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  modal: {
    background: "#fff",
    padding: 20,
    borderRadius: 12,
    width: 520,
  },

  closeBtn: {
    float: "right",
    cursor: "pointer",
  },

  title: {
    fontSize: 20,
    marginBottom: 10,
  },

  tabs: {
    display: "flex",
    gap: 10,
    marginBottom: 12,
  },

  tab: {
    padding: "6px 12px",
    cursor: "pointer",
  },

  activeTab: {
    padding: "6px 12px",
    background: "#1d4ed8",
    color: "#fff",
    borderRadius: 6,
  },

  input: {
    width: "100%",
    padding: 10,
    marginBottom: 10,
  },

  textarea: {
    width: "100%",
    height: 120,
    padding: 10,
    marginBottom: 10,
  },

  tags: {
    marginBottom: 10,
  },

  tag: {
    background: "#eef2ff",
    padding: "4px 8px",
    borderRadius: 10,
    marginRight: 6,
    fontSize: 12,
  },

  publishBtn: {
    width: "100%",
    padding: 10,
    background: "#1d4ed8",
    color: "#fff",
    border: "none",
    borderRadius: 6,
  },

  aiBtn: {
    width: "100%",
    padding: 10,
    marginBottom: 10,
  },

  previewBox: {
    border: "1px solid #ddd",
    padding: 12,
    borderRadius: 8,
  },

  previewTitle: {
    marginBottom: 8,
  },

  previewContent: {
    maxHeight: 200,
    overflow: "auto",
    marginBottom: 10,
    lineHeight: 1.6,
  },

  previewActions: {
    display: "flex",
    gap: 8,
  },

  acceptBtn: {
    flex: 1,
    background: "#16a34a",
    color: "#fff",
    border: "none",
  },

  regenBtn: {
    flex: 1,
  },

  rejectBtn: {
    flex: 1,
  },

  loading: {
    fontStyle: "italic",
  },
};
